#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

long long dp[17][100001];

long long countEasyNumbers(int b, int d) {
    if (d == 1) return b - 1;
    if (dp[b][d] != -1) return dp[b][d];
    long long count = 0;
    for (int i = 1; i < b; i++) {
        if (i % d == 0) {
            count = (count + countEasyNumbers(b, d - 1)) % MOD;
        }
    }
    return dp[b][d] = count;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int b, d;
        scanf("%d %d", &b, &d);
        for (int i = 0; i <= b; i++) {
            for (int j = 0; j <= d; j++) {
                dp[i][j] = -1;
            }
        }
        printf("%lld\n", countEasyNumbers(b, d));
    }
    return 0;
}

