import java.util.Scanner;
public class Main {
    static final int MOD = 1000000007;
    static long[][] dp;
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int b = sc.nextInt();
            int d = sc.nextInt();
            dp = new long[b + 1][d + 1];
            for (int i = 0; i <= b; i++) {
                for (int j = 0; j <= d; j++) {
                    dp[i][j] = -1;
                }
            }
            System.out.println(countEasyNumbers(b, d));
        }
    }
    public static long countEasyNumbers(int b, int d) {
        if (d == 1) return b - 1;
        if (dp[b][d] != -1) return dp[b][d];
        long count = 0;
        for (int i = 1; i < b; i++) {
            if (i % d == 0) {
                count = (count + countEasyNumbers(b, d - 1)) % MOD;
            }
        }
        return dp[b][d] = count;
    }
}

